<script setup lang="ts">
import { PropType, computed, ref, watch } from 'vue'
import { useForm } from 'vuestic-ui'
import { OpsUser, OpsUserRole, UpdateOpsUserRequest } from '../types'
import { validators } from '../../../services/utils'

const props = defineProps({
    opsUser: {
        type: Object as PropType<OpsUser | null>,
        default: null,
    },
    saveButtonLabel: {
        type: String,
        default: 'Save',
    },
})

const emit = defineEmits<{
    (event: 'save', payload: UpdateOpsUserRequest): void
    (event: 'close'): void
}>()

const defaultOpsUser: OpsUser = {
    id: -1,
    firstName: '',
    lastName: '',
    nickname: '',
    userRole: OpsUserRole.Operator,
}

const editOpsUser = ref<OpsUser>({ ...defaultOpsUser })

const isFormHasUnsavedChanges = computed(() => {
    return (
        editOpsUser.value.lastName !== (props.opsUser?.lastName ?? '') ||
        editOpsUser.value.firstName !== (props.opsUser?.firstName ?? '') ||
        editOpsUser.value.nickname !== (props.opsUser?.nickname ?? '') ||
        editOpsUser.value.userRole !== (props.opsUser?.userRole ?? OpsUserRole.Operator)
    )
})

defineExpose({ isFormHasUnsavedChanges })

watch(
    () => props.opsUser,
    (newVal) => {
        if (newVal) {
            editOpsUser.value = {
                id: newVal.id,
                firstName: newVal.firstName ?? '',
                lastName: newVal.lastName ?? '',
                nickname: newVal.nickname ?? '',
                userRole: newVal.userRole ?? OpsUserRole.Operator,
            }
        } else {
            editOpsUser.value = { ...defaultOpsUser }
        }
    },
    { immediate: true },
)

const roleOptions = [
    { text: 'Admin', value: OpsUserRole.Admin },
    { text: 'Operator', value: OpsUserRole.Operator },
    { text: 'Promoter', value: OpsUserRole.Promoter },
]

const { validate } = useForm('edit-ops-user-form')

const onSave = async () => {
    if (!(await validate())) {
        return
    }
    if (!props.opsUser) {
        return
    }

    emit('save', {
        id: props.opsUser.id,
        lastName: editOpsUser.value.lastName || '',
        firstName: editOpsUser.value.firstName || '',
        nickname: editOpsUser.value.nickname || '',
        userRole: editOpsUser.value.userRole,
    })
}
</script>

<template>
    <VaForm
        v-slot="{ isValid }"
        ref="edit-ops-user-form"
        class="flex-col justify-start items-start gap-4 inline-flex w-full"
    >
        <div class="self-stretch flex-col justify-start items-start gap-4 flex">
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput v-model="editOpsUser.lastName" label="姓" class="w-full sm:w-1/2" name="lastName" />
                <VaInput v-model="editOpsUser.firstName" label="名" class="w-full sm:w-1/2" name="firstName" />
            </div>

            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput v-model="editOpsUser.nickname" label="暱稱" class="w-full sm:w-1/2" name="nickname" />
                <VaSelect
                    v-model="editOpsUser.userRole"
                    label="身份別"
                    class="w-full sm:w-1/2"
                    :options="roleOptions"
                    :rules="[validators.required]"
                    value-by="value"
                    text-by="text"
                    name="userRole"
                />
            </div>

            <div class="flex gap-2 flex-col-reverse items-stretch justify-end w-full sm:flex-row sm:items-center">
                <VaButton preset="secondary" color="secondary" @click="$emit('close')">取消</VaButton>
                <VaButton :disabled="!isValid" @click="onSave">{{ saveButtonLabel }}</VaButton>
            </div>
        </div>
    </VaForm>
</template>
