<script setup lang="ts">
import { defineVaDataTableColumns } from 'vuestic-ui'
import { OpsUser, OpsUserRole } from '../types'
import { PropType, computed } from 'vue'
import { Pagination, Sorting } from '../composables/useOpsUsers'
import { useVModel } from '@vueuse/core'

const columns = defineVaDataTableColumns([
    { label: 'ID', key: 'id', sortable: true },
    { label: '姓名', key: 'displayName', sortable: true },
    { label: '暱稱', key: 'nickname', sortable: true },
    { label: 'Email', key: 'email', sortable: true },
    { label: '身份別', key: 'userRole', sortable: true },
    { label: ' ', key: 'actions', align: 'right' },
])

const props = defineProps({
    opsUsers: {
        type: Array as PropType<OpsUser[]>,
        required: true,
    },
    loading: { type: Boolean, default: false },
    pagination: { type: Object as PropType<Pagination>, required: true },
    sortBy: { type: String as PropType<Sorting['sortBy']>, required: true },
    sortingOrder: { type: String as PropType<Sorting['sortingOrder']>, required: true },
})

const emit = defineEmits<{
    (event: 'edit-ops-user', item: OpsUser): void
    (event: 'update:sortBy', sortBy: Sorting['sortBy']): void
    (event: 'update:sortingOrder', sortingOrder: Sorting['sortingOrder']): void
}>()

const sortByVModel = useVModel(props, 'sortBy', emit)
const sortingOrderVModel = useVModel(props, 'sortingOrder', emit)

const totalPages = computed(() => Math.max(1, Math.ceil(props.pagination.total / props.pagination.perPage)))

const roleColors: Record<OpsUserRole, string> = {
    [OpsUserRole.Admin]: 'danger',
    [OpsUserRole.Operator]: 'primary',
    [OpsUserRole.Promoter]: 'warning',
}

const roleLabels: Record<OpsUserRole, string> = {
    [OpsUserRole.Admin]: 'Admin',
    [OpsUserRole.Operator]: 'Operator',
    [OpsUserRole.Promoter]: 'Promoter',
}

const getDisplayName = (user: OpsUser) => {
    const fullName = `${user.lastName || ''}${user.firstName || ''}`.trim()
    if (fullName) {
        return fullName
    }
    if (user.nickname) {
        return user.nickname
    }
    return '-'
}
</script>

<template>
    <VaDataTable
        v-model:sort-by="sortByVModel"
        v-model:sorting-order="sortingOrderVModel"
        :columns="columns"
        :items="opsUsers"
        :loading="$props.loading"
    >
        <template #cell(displayName)="{ rowData }">
            <div class="max-w-[200px] ellipsis">
                {{ getDisplayName(rowData as OpsUser) }}
            </div>
        </template>

        <template #cell(nickname)="{ rowData }">
            <div class="max-w-[140px] ellipsis">{{ rowData.nickname || '-' }}</div>
        </template>

        <template #cell(email)="{ rowData }">
            <div class="max-w-[240px] ellipsis">{{ rowData.email || '-' }}</div>
        </template>

        <template #cell(userRole)="{ rowData }">
            <VaBadge
                v-if="rowData.userRole"
                :text="roleLabels[rowData.userRole as OpsUserRole]"
                :color="roleColors[rowData.userRole as OpsUserRole]"
            />
            <span v-else>-</span>
        </template>

        <template #cell(actions)="{ rowData }">
            <div class="flex gap-2 justify-end">
                <VaButton
                    preset="primary"
                    size="small"
                    icon="mso-edit"
                    aria-label="Edit ops user"
                    @click="$emit('edit-ops-user', rowData as OpsUser)"
                />
            </div>
        </template>
    </VaDataTable>

    <div class="flex flex-col-reverse md:flex-row gap-2 justify-between items-center py-2">
        <div>
            <b>{{ $props.pagination.total }} results.</b>
            Results per page
            <VaSelect v-model="$props.pagination.perPage" class="!w-20" :options="[10, 50, 100]" />
        </div>

        <div v-if="totalPages > 1" class="flex">
            <VaButton
                preset="secondary"
                icon="va-arrow-left"
                aria-label="Previous page"
                :disabled="$props.pagination.page === 1"
                @click="$props.pagination.page--"
            />
            <VaButton
                preset="secondary"
                icon="va-arrow-right"
                class="mr-2"
                aria-label="Next page"
                :disabled="$props.pagination.page === totalPages"
                @click="$props.pagination.page++"
            />
            <VaPagination
                v-model="$props.pagination.page"
                buttons-preset="secondary"
                :pages="totalPages"
                :visible-pages="5"
                :boundary-links="false"
                :direction-links="false"
            />
        </div>
    </div>
</template>
