<script setup lang="ts">
import { computed, ref, watch } from 'vue'
import { useForm } from 'vuestic-ui'
import { CreateOpsUserInviteRequest, OpsUserRole } from '../types'
import { validators } from '../../../services/utils'

defineProps({
    saveButtonLabel: {
        type: String,
        default: '新增',
    },
})

const emit = defineEmits<{
    (event: 'save', payload: CreateOpsUserInviteRequest): void
    (event: 'close'): void
}>()

const defaultInviteRequest: CreateOpsUserInviteRequest = {
    email: '',
    userRole: OpsUserRole.Operator,
}

const inviteRequest = ref<CreateOpsUserInviteRequest>({ ...defaultInviteRequest })
const emailErrorMessage = ref('')

const roleOptions = [
    { text: 'Admin', value: OpsUserRole.Admin },
    { text: 'Operator', value: OpsUserRole.Operator },
    { text: 'Promoter', value: OpsUserRole.Promoter },
]

const isFormHasUnsavedChanges = computed(() => {
    return (
        inviteRequest.value.email !== defaultInviteRequest.email ||
        inviteRequest.value.userRole !== defaultInviteRequest.userRole
    )
})

const reset = () => {
    inviteRequest.value = { ...defaultInviteRequest }
    emailErrorMessage.value = ''
}

const setEmailError = (message: string) => {
    emailErrorMessage.value = message
}

watch(
    () => inviteRequest.value.email,
    () => {
        emailErrorMessage.value = ''
    },
)

defineExpose({
    isFormHasUnsavedChanges,
    reset,
    setEmailError,
})

const { validate } = useForm('invite-ops-user-form')

const onSave = async () => {
    emailErrorMessage.value = ''

    if (!(await validate())) {
        return
    }

    emit('save', {
        email: inviteRequest.value.email.trim(),
        userRole: inviteRequest.value.userRole,
    })
}
</script>

<template>
    <VaForm
        v-slot="{ isValid }"
        ref="invite-ops-user-form"
        class="flex-col justify-start items-start gap-4 inline-flex w-full"
    >
        <div class="self-stretch flex-col justify-start items-start gap-4 flex">
            <VaInput
                v-model="inviteRequest.email"
                label="Email"
                class="w-full"
                name="email"
                :rules="[validators.required, validators.email]"
                :error="Boolean(emailErrorMessage)"
                :error-messages="emailErrorMessage ? [emailErrorMessage] : []"
            />

            <VaSelect
                v-model="inviteRequest.userRole"
                label="身份別"
                class="w-full"
                :options="roleOptions"
                :rules="[validators.required]"
                value-by="value"
                text-by="text"
                name="userRole"
            />

            <div class="flex gap-2 flex-col-reverse items-stretch justify-end w-full sm:flex-row sm:items-center">
                <VaButton preset="secondary" color="secondary" @click="$emit('close')"> 取消 </VaButton>
                <VaButton :disabled="!isValid" @click="onSave">{{ saveButtonLabel }}</VaButton>
            </div>
        </div>
    </VaForm>
</template>
