<script setup lang="ts">
import { ref } from 'vue'
import OpsUsersTable from './widgets/OpsUsersTable.vue'
import EditOpsUserForm from './widgets/EditOpsUserForm.vue'
import InviteOpsUserForm from './widgets/InviteOpsUserForm.vue'
import { CreateOpsUserInviteRequest, OpsUser, UpdateOpsUserRequest } from './types'
import { useOpsUsers } from './composables/useOpsUsers'
import { useModal, useToast } from 'vuestic-ui'

const doShowEditModal = ref(false)
const doShowInviteModal = ref(false)
const { opsUsers, isLoading, filters, sorting, pagination, ...opsUsersApi } = useOpsUsers()

const opsUserToEdit = ref<OpsUser | null>(null)

const showEditModal = (item: OpsUser) => {
    opsUserToEdit.value = item
    doShowEditModal.value = true
}

const showInviteModal = () => {
    inviteFormRef.value?.reset()
    doShowInviteModal.value = true
}

const { init: notify } = useToast()

const onSaved = async (payload: UpdateOpsUserRequest) => {
    try {
        await opsUsersApi.update(payload)
        notify({
            message: '後台用戶資料已更新',
            color: 'success',
        })
    } catch (error) {
        notify({
            message: '更新失敗，請稍後再試',
            color: 'danger',
        })
    }
}

const editFormRef = ref()
const inviteFormRef = ref()
const { confirm } = useModal()

const beforeModalClose = async (hide: () => unknown) => {
    if (editFormRef.value?.isFormHasUnsavedChanges) {
        const agreed = await confirm({
            maxWidth: '380px',
            message: '表單尚未儲存，確定要關閉嗎？',
            size: 'small',
        })
        if (agreed) {
            hide()
        }
    } else {
        hide()
    }
}

const beforeInviteModalClose = async (hide: () => unknown) => {
    if (inviteFormRef.value?.isFormHasUnsavedChanges) {
        const agreed = await confirm({
            maxWidth: '380px',
            message: '表單尚未儲存，確定要關閉嗎？',
            size: 'small',
        })
        if (agreed) {
            inviteFormRef.value?.reset()
            hide()
        }
    } else {
        inviteFormRef.value?.reset()
        hide()
    }
}

const onInvited = async (payload: CreateOpsUserInviteRequest, onSuccess: () => void) => {
    try {
        await opsUsersApi.invite(payload)
        notify({
            message: '後台用戶邀請已送出',
            color: 'success',
        })
        inviteFormRef.value?.reset()
        onSuccess()
    } catch (error: any) {
        const statusCode = error?.response?.status
        if (statusCode === 409) {
            inviteFormRef.value?.setEmailError('Email 已存在')
            return
        }

        notify({
            message: '邀請失敗，請稍後再試',
            color: 'danger',
        })
    }
}
</script>

<template>
    <h1 class="page-title">後台用戶管理</h1>

    <VaCard>
        <VaCardContent>
            <div class="flex flex-col md:flex-row gap-2 mb-2 justify-between">
                <div class="flex flex-col md:flex-row gap-2 justify-start w-full md:w-auto">
                    <VaInput
                        v-model="filters.search"
                        placeholder="Search by name / nickname / email"
                        class="w-full md:w-96"
                    >
                        <template #prependInner>
                            <VaIcon name="search" color="secondary" size="small" />
                        </template>
                    </VaInput>
                </div>

                <VaButton @click="showInviteModal">新增後台用戶</VaButton>
            </div>

            <OpsUsersTable
                v-model:sort-by="sorting.sortBy"
                v-model:sorting-order="sorting.sortingOrder"
                :ops-users="opsUsers"
                :loading="isLoading"
                :pagination="pagination"
                @editOpsUser="showEditModal"
            />
        </VaCardContent>
    </VaCard>

    <VaModal
        v-slot="{ cancel, ok }"
        v-model="doShowEditModal"
        size="small"
        mobile-fullscreen
        close-button
        hide-default-actions
        :before-cancel="beforeModalClose"
    >
        <h1 class="va-h5">編輯後台用戶</h1>
        <EditOpsUserForm
            ref="editFormRef"
            :ops-user="opsUserToEdit"
            save-button-label="儲存"
            @close="cancel"
            @save="
                (item) => {
                    onSaved(item)
                    ok()
                }
            "
        />
    </VaModal>

    <VaModal
        v-slot="{ cancel, ok }"
        v-model="doShowInviteModal"
        size="small"
        mobile-fullscreen
        close-button
        hide-default-actions
        :before-cancel="beforeInviteModalClose"
    >
        <h1 class="va-h5">新增後台用戶</h1>
        <InviteOpsUserForm
            ref="inviteFormRef"
            save-button-label="新增"
            @close="cancel"
            @save="(item) => onInvited(item, ok)"
        />
    </VaModal>
</template>
