import { Ref, computed, ref, watch } from 'vue'
import { watchIgnorable } from '@vueuse/core'
import api from '../../../services/api'
import { CreateOpsUserInviteRequest, OpsUser, UpdateOpsUserRequest } from '../types'

export type Pagination = {
    page: number
    perPage: number
    total: number
}

export type Sorting = {
    sortBy: keyof OpsUser | 'displayName' | undefined
    sortingOrder: 'asc' | 'desc' | null
}

export type Filters = {
    search: string
}

const makePaginationRef = () => ref<Pagination>({ page: 1, perPage: 10, total: 0 })
const makeSortingRef = () => ref<Sorting>({ sortBy: 'id', sortingOrder: null })
const makeFiltersRef = () => ref<Partial<Filters>>({ search: '' })

const normalizeText = (value?: string | null) => (value || '').trim().toLowerCase()

const getDisplayName = (user: OpsUser) => {
    const fullName = `${user.lastName || ''}${user.firstName || ''}`.trim()
    if (fullName) {
        return fullName
    }
    if (user.nickname) {
        return user.nickname
    }
    return '-'
}

export const useOpsUsers = (options?: {
    pagination?: Ref<Pagination>
    sorting?: Ref<Sorting>
    filters?: Ref<Partial<Filters>>
}) => {
    const isLoading = ref(false)
    const opsUsers = ref<OpsUser[]>([])

    const { filters = makeFiltersRef(), sorting = makeSortingRef(), pagination = makePaginationRef() } = options || {}

    const filteredOpsUsers = computed(() => {
        const keyword = normalizeText(filters.value.search)
        if (!keyword) {
            return opsUsers.value
        }

        return opsUsers.value.filter((user) => {
            const fields = [getDisplayName(user), user.nickname || '', user.email || '']
            return fields.some((field) => normalizeText(field).includes(keyword))
        })
    })

    const sortedOpsUsers = computed(() => {
        const list = [...filteredOpsUsers.value]
        const sortBy = sorting.value.sortBy
        const sortOrder = sorting.value.sortingOrder

        if (!sortBy || !sortOrder) {
            return list
        }

        const direction = sortOrder === 'asc' ? 1 : -1

        list.sort((a, b) => {
            const aValue = sortBy === 'displayName' ? getDisplayName(a) : a[sortBy as keyof OpsUser] ?? ''
            const bValue = sortBy === 'displayName' ? getDisplayName(b) : b[sortBy as keyof OpsUser] ?? ''

            if (typeof aValue === 'number' && typeof bValue === 'number') {
                return (aValue - bValue) * direction
            }

            return String(aValue).localeCompare(String(bValue)) * direction
        })

        return list
    })

    const pagedOpsUsers = computed(() => {
        const start = (pagination.value.page - 1) * pagination.value.perPage
        const end = start + pagination.value.perPage
        return sortedOpsUsers.value.slice(start, end)
    })

    watch(
        [filteredOpsUsers, () => pagination.value.perPage],
        () => {
            pagination.value.total = filteredOpsUsers.value.length
            const totalPages = Math.max(1, Math.ceil(pagination.value.total / pagination.value.perPage))
            if (pagination.value.page > totalPages) {
                pagination.value.page = totalPages
            }
        },
        { immediate: true },
    )

    watch(
        [filters, sorting, () => pagination.value.perPage],
        () => {
            pagination.value.page = 1
        },
        { deep: true },
    )

    const fetch = async () => {
        isLoading.value = true
        try {
            const { data } = await api.getOpsUsers()
            opsUsers.value = data.data || []
            pagination.value.total = (data.data || []).length
        } finally {
            isLoading.value = false
        }
    }

    // Keep the same composable contract style with watchIgnorable, without refetching on sort/page.
    watchIgnorable([pagination, sorting], () => undefined, { deep: true })

    fetch()

    return {
        isLoading,
        filters,
        sorting,
        pagination,
        opsUsers: pagedOpsUsers,
        fetch,
        getDisplayName,

        async update(payload: UpdateOpsUserRequest) {
            isLoading.value = true
            try {
                await api.updateOpsUser(payload)
                await fetch()
            } finally {
                isLoading.value = false
            }
        },

        async invite(payload: CreateOpsUserInviteRequest) {
            isLoading.value = true
            try {
                await api.axiosInstance.post('/ops-user/invite', payload)
                await fetch()
            } finally {
                isLoading.value = false
            }
        },
    }
}
